def header(title,desc,body):
 links=''.join(f'<a href="{u}">{l}</a>' for u,l in nav); schema=json.dumps({"@context":"https://schema.org","@type":"Electrician","name":"JAG Electric","telephone":"+1-620-714-1125","email":email,"address":{"@type":"PostalAddress","streetAddress":"807 E 7th St","addressLocality":"Galena","addressRegion":"KS","postalCode":"66739"},"areaServed":["Galena KS","Pittsburg KS","Joplin MO","Frontenac KS","Girard KS"],"url":BASE})
