def hero(k,t,d): return f'<main class="page"><section class="page-hero"><p class="eyebrow">⚡ {esc(k)}</p><h1>{esc(t)}</h1><p>{esc(d)}</p></section>'
def cta(label='electrical work'): return f'<section class="cta"><h2>Ready to get the {label} scoped?</h2><p>Call JAG Electric or build a prep summary first. The fastest useful call is a clear one.</p><div class="hero-actions"><a class="btn primary" href="tel:{tel}">{phone}</a><a class="btn ghost" href="/estimate-prep">Estimate prep</a></div></section>'
