 return header('Electrical Services | JAG Electric','JAG Electric service index for panel upgrades, rewiring, lighting, outlets, remodel wiring, and commercial electrical service.',hero('Service index','Electrical service pages with real local depth.','Every service page carries practical customer-facing copy, electrical photos, and clear next steps for Galena, Pittsburg, and nearby communities.')+f'<section class="service-grid page-grid">{cards}</section>'+cta()+'</main>')
