def write(route,txt):
 d=DIST if route=='/' else DIST/route.strip('/'); d.mkdir(parents=True,exist_ok=True); (d/'index.html').write_text(txt)
def main():
 if DIST.exists(): shutil.rmtree(DIST)
 DIST.mkdir(); shutil.copytree(ROOT/'public'/'assets',DIST/'assets'); shutil.copy(ROOT/'src'/'styles.css',DIST/'assets'/'site.css')
 (DIST/'assets'/'site.js').write_text("""const b=document.getElementById('mobile-menu-toggle'),n=document.getElementById('mobile-nav');if(b&&n)b.onclick=()=>n.classList.toggle('open');function upd(){const p=document.getElementById('project-type'),l=document.getElementById('project-location'),i=document.getElementById('project-issue'),s=document.getElementById('summary-text'),e=document.getElementById('email-notes');if(!s)return;const txt=`JAG Electric call prep: ${p.value} near ${l.value}. Main issue: ${i.value}. Please confirm scheduling, photos needed, and whether this is repair, remodel, or new work.`;s.textContent=txt;if(e)e.href='mailto:jag.electric@yahoo.com?subject=Electrical%20estimate%20prep&body='+encodeURIComponent(txt)}['project-type','project-location','project-issue'].forEach(id=>{const x=document.getElementById(id);if(x)x.addEventListener('input',upd)});upd();""")
 routes={'/':home(),'/services':index_services(),'/service-area':index_area(),'/about':simple('about'),'/reviews':simple('reviews'),'/estimate-prep':simple('estimate'),'/photo-credits':photo_credits()}
 for s in services: routes['/services/'+s[0]]=service_page(*s)
 for t in towns: routes['/service-area/'+t[0]]=city_page(*t)
 for r,t in routes.items(): write(r,t)
 (DIST/'sitemap.xml').write_text('<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'+''.join(f'<url><loc>{BASE}{r}</loc></url>\n' for r in routes)+'</urlset>')
 (DIST/'robots.txt').write_text(f'User-agent: *\nAllow: /\nSitemap: {BASE}/sitemap.xml\n')
 print('Generated routes:',len(routes));
 for r,t in routes.items(): print(r,wc(t))
if __name__=='__main__': main()
